import { Routes } from '@angular/router';
import { createGuardedGridRoute } from '../../../../shared/utils';
import { vendorsGuard } from '../../guards';
import { AdminGridContainerComponent } from '../admin-grid-container/admin-grid-container.component';
import { AdminTreetableContainerComponent } from '../admin-treetable-container/admin-treetable-container.component';
import { DistributorContainerComponent } from './distributor-container/distributor-container.component';

export const ADMIN_DISTRIBUTOR_ROUTES: Routes = [
  {
    path: '',
    component: DistributorContainerComponent,
    children: [
      {
        path: '',
        redirectTo: 'details',
        pathMatch: 'full',
      },
      {
        path: 'details',
        loadChildren: () =>
          import('./distributor-details/distributor-details.routes').then(
            (m) => m.ADMIN_DISTRIBUTOR_DETAILS_ROUTES,
          ),
        data: { nestedContentScrollable: true },
      },
      {
        path: 'providers',
        children: [
          {
            path: '',
            redirectTo: 'distributor-device-providers',
            pathMatch: 'full',
          },
          {
            path: ':type',
            component: AdminGridContainerComponent,
          },
        ],
      },
      {
        path: 'profiles',
        children: [
          {
            path: '',
            redirectTo: 'distributor-company-groups',
            pathMatch: 'full',
          },
          {
            path: 'distributor-company-groups',
            component: AdminTreetableContainerComponent,
            data: { type: 'distributor-company-groups' },
          },
          {
            path: 'distributor-company-groups/:entityType/:entityId',
            component: AdminTreetableContainerComponent,
            data: { type: 'distributor-company-groups' },
          },
          {
            path: ':type',
            component: AdminGridContainerComponent,
          },
          {
            path: ':type/:entityType/:entityId',
            component: AdminGridContainerComponent,
          },
        ],
      },
      {
        path: 'accounts',
        children: [
          {
            path: '',
            redirectTo: 'distributor-users',
            pathMatch: 'full',
          },
          {
            path: ':type',
            component: AdminGridContainerComponent,
          },
          {
            path: ':type/:entityType/:entityId',
            component: AdminGridContainerComponent,
          },
        ],
      },
      ...createGuardedGridRoute(
        'vendors',
        vendorsGuard,
        AdminGridContainerComponent,
      ),
    ],
  },
];
